#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,X,Y; scanf("%lld %lld %lld %lld", &A,&B,&X,&Y);
        long long D = B - A;
        if(D >= 0){
            if(D <= X) printf("YES\n");
            else printf("NO\n");
        }else{
            if(-D <= Y) printf("YES\n");
            else printf("NO\n");
        }
    }
    return 0;
}

