#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); X = int(next(it)); Y = int(next(it))
        D = B - A
        if D >= 0:
            out.append("YES" if D <= X else "NO")
        else:
            out.append("YES" if -D <= Y else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

